using Microsoft.EntityFrameworkCore; using PollsApi.Models; namespace PollsApi.Data { public class AppDbContext : DbContext { public AppDbContext(DbContextOptions<AppDbContext> options) : base(options) { } public DbSet<Poll> Polls { get; set; } public DbSet<Option> Options { get; set; } public DbSet<Vote> Votes { get; set; } protected override void OnModelCreating(ModelBuilder modelBuilder) { modelBuilder.Entity<Vote>().HasIndex(v = { v.PollId, v.SessionId }).IsUnique(); } } } 
